        // --- Singleton Theme Manager ---
        const ThemeManager = (function() {
            let instance; // Holds the single instance

            function init() {
                // Private variables and methods
                const THEME_KEY = 'app-theme';
                const DARK_THEME_CLASS = 'dark-theme';
                const LIGHT_THEME_CLASS = 'light-theme';
                let currentTheme;

                // Function to apply the theme to the body
                function applyTheme(theme) {
                    const body = document.body;
                    if (theme === 'dark') {
                        body.classList.add(DARK_THEME_CLASS);
                        body.classList.remove(LIGHT_THEME_CLASS);
                    } else {
                        body.classList.add(LIGHT_THEME_CLASS);
                        body.classList.remove(DARK_THEME_CLASS);
                    }
                    currentTheme = theme;
                    localStorage.setItem(THEME_KEY, theme); // Persist theme
                    console.log(`Theme set to: ${theme}`);
                }

                // Function to initialize theme from localStorage or system preference
                function initializeTheme() {
                    const savedTheme = localStorage.getItem(THEME_KEY);
                    if (savedTheme) {
                        applyTheme(savedTheme);
                    } else {
                        // Check for system preference
                        const prefersDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
                        applyTheme(prefersDark ? 'dark' : 'light');
                    }
                }

                // Public interface
                return {
                    toggleTheme: function() {
                        const newTheme = (currentTheme === 'dark') ? 'light' : 'dark';
                        applyTheme(newTheme);
                    },
                    getCurrentTheme: function() {
                        return currentTheme;
                    },
                    // This method is called once to set up the initial theme
                    setup: function() {
                        initializeTheme();
                    }
                };
            }

            return {
                // Get the singleton instance
                getInstance: function() {
                    if (!instance) {
                        instance = init();
                    }
                    return instance;
                }
            };
        })();

        // --- Application Logic ---
        document.addEventListener('DOMContentLoaded', () => {
            // Get the singleton instance of ThemeManager
            const themeManager = ThemeManager.getInstance();

            // Initialize the theme based on saved preference or system default
            themeManager.setup();

            // Attach event listener to the toggle button
            const themeToggleButton = document.getElementById('theme-toggle');
            if (themeToggleButton) {
