            }

            // Getter for current theme
            get currentTheme() {
                return this._currentTheme;
            }

            // Setter for theme, updates localStorage and applies theme
            setTheme(theme) {
                if (this._currentTheme !== theme) {
                    this._currentTheme = theme;
                    localStorage.setItem('theme', theme);
                    this.applyTheme();
                }
            }

