            // JavaScript for Singleton Theme Manager and interactions

            // 1. Singleton ThemeManager Class
            class ThemeManager {
                constructor() {
                    if (ThemeManager.instance) {
                        return ThemeManager.instance; // Ensure only one instance
                    }

                    this._theme = localStorage.getItem('appTheme') || 'light'; // Load from localStorage or default
                    this._applyThemeToBody(); // Apply initial theme on load

                    ThemeManager.instance = this;
                }

                static getInstance() {
                    if (!ThemeManager.instance) {
                        ThemeManager.instance = new ThemeManager();
                    }
                    return ThemeManager.instance;
                }

                getTheme() {
                    return this._theme;
                }

                toggleTheme() {
                    this._theme = (this._theme === 'light') ? 'dark' : 'light';
                    localStorage.setItem('appTheme', this._theme); // Persist theme
                    this._applyThemeToBody();
                    this._updateThemeStatusDisplay(); // Update any status displays
                    console.log(`Theme toggled to: ${this._theme}`);
                }

                _applyThemeToBody() {
                    const body = document.body;
                    body.classList.remove('light-theme', 'dark-theme');
                    body.classList.add(`${this._theme}-theme`);
                }

                _updateThemeStatusDisplay() {
                    const statusElement = document.getElementById('currentThemeStatus');
                    if (statusElement) {
                        statusElement.textContent = this._theme.charAt(0).toUpperCase() + this._theme.slice(1);
                    }
                }
