    <script>
        // The Singleton ThemeManager
        const ThemeManager = (function() {
            let instance;
            const THEME_STORAGE_KEY = 'app_theme';
            const DEFAULT_THEME = 'light';

            function init() {
                // Private methods and properties
                let currentTheme = localStorage.getItem(THEME_STORAGE_KEY) || DEFAULT_THEME;

                const applyThemeToDOM = (theme) => {
                    document.documentElement.setAttribute('data-theme', theme);
                    const themeIcon = document.getElementById('theme-icon');
                    const themeText = document.getElementById('theme-text');

                    if (themeIcon && themeText) {
                        if (theme === 'dark') {
                            themeIcon.textContent = '🌙';
                            themeText.textContent = 'Switch to Light Theme';
                        } else {
                            themeIcon.textContent = '☀️';
                            themeText.textContent = 'Switch to Dark Theme';
                        }
                    }
                };

                const saveTheme = (theme) => {
                    localStorage.setItem(THEME_STORAGE_KEY, theme);
                };

                return {
                    // Public methods
                    getTheme: function() {
                        return currentTheme;
                    },
                    setTheme: function(theme) {
                        if (theme === 'light' || theme === 'dark') {
                            currentTheme = theme;
                            saveTheme(theme);
                            applyThemeToDOM(theme);
                        } else {
                            console.warn(`Invalid theme: ${theme}. Theme must be 'light' or 'dark'.`);
                        }
                    },
                    toggleTheme: function() {
                        const newTheme = currentTheme === 'light' ? 'dark' : 'light';
                        this.setTheme(newTheme);
                    },
                    // Apply the initially loaded theme
                    initializeTheme: function() {
                        applyThemeToDOM(currentTheme);
                    }
                };
            }

            return {
                getInstance: function() {
                    if (!instance) {
                        instance = init();
                    }
                    return instance;
                }
            };
        })();

        // DOMContentLoaded ensures the DOM is fully loaded before we try to access elements
        document.addEventListener('DOMContentLoaded', () => {
            const themeManager = ThemeManager.getInstance();
            themeManager.initializeTheme(); // Apply the theme stored in localStorage or default

            const themeToggleButton = document.getElementById('theme-toggle');
            if (themeToggleButton) {
                themeToggleButton.addEventListener('click', () => {
                    themeManager.toggleTheme();
                });
            }
        });
    </script>
