    <script>
        // --- Singleton Theme Manager ---
        class ThemeManager {
            constructor() {
                if (ThemeManager.instance) {
                    return ThemeManager.instance;
                }
                this._currentTheme = 'light'; // Default theme
                this._themeToggleBtn = document.getElementById('theme-toggle');
                ThemeManager.instance = this;
            }

            static getInstance() {
                if (!ThemeManager.instance) {
                    ThemeManager.instance = new ThemeManager();
                }
                return ThemeManager.instance;
            }

            get currentTheme() {
                return this._currentTheme;
            }

            setTheme(theme) {
                if (theme !== 'light' && theme !== 'dark') {
                    console.warn(`Invalid theme "${theme}". Setting to default "light".`);
                    theme = 'light';
                }

                this._currentTheme = theme;
                document.body.classList.toggle('dark-theme', theme === 'dark');
                this._updateToggleButtonText();
                localStorage.setItem('theme', theme); // Persist theme choice
            }

            toggleTheme() {
                const newTheme = this._currentTheme === 'light' ? 'dark' : 'light';
                this.setTheme(newTheme);
            }

            _updateToggleButtonText() {
                if (this._themeToggleBtn) {
                    this._themeToggleBtn.textContent = `Toggle Theme: ${this._currentTheme.charAt(0).toUpperCase() + this._currentTheme.slice(1)}`;
                }
            }

            initialize() {
                // Check local storage first
                const savedTheme = localStorage.getItem('theme');
                if (savedTheme) {
                    this.setTheme(savedTheme);
                } else if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
                    // Check system preference
                    this.setTheme('dark');
                } else {
                    // Default to light
                    this.setTheme('light');
                }

                // Add event listener for the toggle button
                if (this._themeToggleBtn) {
                    this._themeToggleBtn.addEventListener('click', () => this.toggleTheme());
                }
            }
        }

        // --- Initialize the Theme Manager and Theme ---
        document.addEventListener('DOMContentLoaded', () => {
            const themeManager = ThemeManager.getInstance();
            themeManager.initialize();
        });
    </script>
</body>
