    <script>
        // --- Singleton ThemeManager Implementation ---
        class ThemeManager {
            constructor() {
                if (ThemeManager.instance) {
                    return ThemeManager.instance;
                }

                this.themeKey = 'theme';
                this.defaultTheme = 'light-theme';
                this.currentTheme = localStorage.getItem(this.themeKey) || this.defaultTheme;

                // Apply initial theme immediately
                document.body.classList.add(this.currentTheme);
                this._updateToggleState();

                ThemeManager.instance = this;
            }

            static getInstance() {
                if (!ThemeManager.instance) {
                    ThemeManager.instance = new ThemeManager();
                }
                return ThemeManager.instance;
            }

            setTheme(themeName) {
                if (this.currentTheme === themeName) {
                    return; // No change needed
                }

                document.body.classList.remove('light-theme', 'dark-theme');
                document.body.classList.add(themeName);
                localStorage.setItem(this.themeKey, themeName);
                this.currentTheme = themeName;
                this._updateToggleState();
                console.log(`Theme switched to: ${themeName}`);
            }

            toggleTheme() {
                const newTheme = this.currentTheme === 'dark-theme' ? 'light-theme' : 'dark-theme';
                this.setTheme(newTheme);
            }

            getTheme() {
                return this.currentTheme;
            }

            _updateToggleState() {
                const themeSwitch = document.getElementById('theme-switch');
                if (themeSwitch) {
                    themeSwitch.checked = (this.currentTheme === 'dark-theme');
                }
            }
        }

        // --- Event Listeners and Initial Setup ---
        document.addEventListener('DOMContentLoaded', () => {
            const themeManager = ThemeManager.getInstance(); // Get the singleton instance
            const themeSwitch = document.getElementById('theme-switch');
            const actionButton = document.getElementById('actionButton');

            // Set initial toggle state based on loaded theme
            themeManager._updateToggleState();

            // Event listener for the theme switch
            if (themeSwitch) {
                themeSwitch.addEventListener('change', () => {
                    themeManager.toggleTheme();
                });
            }

            // Example of another element interacting with the theme state (optional)
            if (actionButton) {
                actionButton.addEventListener('click', () => {
                    alert(`Current theme is: ${themeManager.getTheme()}`);
                });
            }
        });
    </script>
